document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("contact-form");e&&e.addEventListener("submit",async a=>{a.preventDefault();const s=document.getElementById("contact-name").value,c=document.getElementById("contact-email").value,r=document.getElementById("contact-subject").value,d=document.getElementById("contact-message").value,t=e.querySelector('button[type="submit"]'),l=t.textContent;t.textContent="Odes\xEDl\xE1m...",t.disabled=!0;try{const n=await(await fetch("/api/contact/contact",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({name:s,email:c,subject:r,message:d})})).json();n.success?(alert(n.message||"Zpr\xE1va byla odesl\xE1na!"),e.reset()):alert(n.error||"Chyba p\u0159i odes\xEDl\xE1n\xED zpr\xE1vy.")}catch(o){console.error("Contact Form Error:",o),alert("Chyba p\u0159i odes\xEDl\xE1n\xED zpr\xE1vy. Zkuste to pros\xEDm pozd\u011Bji.")}finally{t.textContent=l,t.disabled=!1}})});
